# Category: xxe

import xml.etree.ElementTree as ET

def parse_config(file_path):
    settings = {}

    tree = ET.parse(file_path)
    root = tree.getroot()

    for elem in root:
        key = elem.tag.split('}')[-1]
        value = elem.text
        if value:  # Skip elements without text content
            settings[key] = value

    return settings